mapper.select:
SELECT
    sido,
    sigungu,
    dong,
    ContYear AS contYear,
    COUNT(ContYear) AS cnt
FROM KR_REAL_INFO
WHERE sido = #{sido}

    AND sigungu = #{sigungu}


    AND dong = #{dong}

AND ContYear BETWEEN #{startYearMonth} AND #{endYearMonth}
GROUP BY sido, sigungu, dong, ContYear
ORDER BY ContYear ASC

SELECT
    ContYear AS contYear,
    COUNT(ContYear) AS cnt
FROM KR_REAL_INFO
WHERE sido = #{sido}

    AND sigungu = #{sigungu}


    AND dong = #{dong}

AND ContYear BETWEEN #{startYearMonth} AND #{endYearMonth}
GROUP BY ContYear
ORDER BY ContYear ASC

SELECT DISTINCT city, sido, sigungu, dong, dangi, DediArea AS dediArea, ContDate AS contDate, amount, [Floor] AS floor FROM KR_REAL_INFO WHERE sido = #{sido}
AND sigungu = #{sigungu}
AND dong = #{dong}
AND dangi = #{dangi}
AND ContYear BETWEEN #{startYearMonth} AND #{endYearMonth} ORDER BY city, dangi, DediArea

SELECT city, sido, sigungu, dong, dangi, DediArea AS dediArea, AVG(CAST(REPLACE(amount, ',', '') AS INT)) AS avgAmount, COUNT(*) AS cnt, ContYear AS contYear FROM KR_REAL_INFO WHERE sido = #{sido}
AND sigungu = #{sigungu}
AND dong = #{dong}
AND dangi = #{dangi}
AND DediArea = #{dediArea}
GROUP BY city, sido, sigungu, dong, dangi, DediArea, ContYear ORDER BY city, dangi, DediArea
